import { useState, useRef } from 'react';

const C = {
  bg: '#0B0F14',
  surface: '#0F1620',
  border: '#1F2A37',
  text: '#E5E7DB',
  muted: '#90A3AF',
  green: '#22C55E',
  red: '#EF4444',
  blue: '#60A5FA',
  amber: '#F59E0B',
  purple: '#A78BFA',
};
const font = "'JetBrains Mono', monospace";

const STEPS = [
  { id: 1, label: 'Parsing intent...' },
  { id: 2, label: 'Generating signals...' },
  { id: 3, label: 'Running backtest...' },
  { id: 4, label: 'Optimizing parameters...' },
  { id: 5, label: 'Complete' },
];

// Results populated after backtest completes
const MOCK_RESULTS = {
  name: '--',
  sharpe: '--',
  pf: '--',
  winRate: '--',
  cagr: '--',
  maxDD: '--',
  trades: '--',
};

const PLACEHOLDER = 'e.g. Mean reversion on large cap tech stocks using RSI and Bollinger Bands with 5-day holding period...';

function Spinner() {
  return (
    <svg width={14} height={14} viewBox="0 0 14 14" style={{ animation: 'spin 0.8s linear infinite', display: 'inline-block' }}>
      <style>{`@keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }`}</style>
      <circle cx={7} cy={7} r={5} fill="none" stroke={C.blue} strokeWidth={2} strokeDasharray="20 12" />
    </svg>
  );
}

function CheckIcon() {
  return (
    <svg width={14} height={14} viewBox="0 0 14 14" style={{ display: 'inline-block' }}>
      <circle cx={7} cy={7} r={6} fill={C.green + '33'} />
      <path d="M4 7l2.5 2.5L10 4.5" stroke={C.green} strokeWidth={1.8} fill="none" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function MetricTile({ label, value, color }) {
  return (
    <div style={{
      background: C.bg,
      border: `1px solid ${C.border}`,
      borderRadius: 10,
      padding: '10px 14px',
      flex: '1 1 100px',
    }}>
      <div style={{ fontSize: 10, color: C.muted, marginBottom: 4, textTransform: 'uppercase', letterSpacing: 0.8 }}>{label}</div>
      <div style={{ fontSize: 16, fontWeight: 700, color: color || C.text }}>{value}</div>
    </div>
  );
}

export default function AgenticStrategyRunner() {
  const [description, setDescription] = useState('');
  const [phase, setPhase] = useState('idle'); // idle | running | done | error
  const [currentStep, setCurrentStep] = useState(0);
  const [completedSteps, setCompletedSteps] = useState([]);
  const [deployed, setDeployed] = useState(false);
  const timeoutRefs = useRef([]);

  const clearTimeouts = () => {
    timeoutRefs.current.forEach(t => clearTimeout(t));
    timeoutRefs.current = [];
  };

  const handleBuild = () => {
    if (!description.trim()) return;
    clearTimeouts();
    setPhase('running');
    setCurrentStep(1);
    setCompletedSteps([]);
    setDeployed(false);

    let delay = 0;
    STEPS.forEach((step, idx) => {
      const stepDelay = idx === STEPS.length - 1 ? delay + 600 : delay + 800;
      delay = stepDelay;
      const t = setTimeout(() => {
        setCompletedSteps(prev => [...prev, step.id]);
        if (idx < STEPS.length - 1) {
          setCurrentStep(STEPS[idx + 1].id);
        } else {
          setPhase('done');
          setCurrentStep(0);
        }
      }, stepDelay);
      timeoutRefs.current.push(t);
    });
  };

  const handleReset = () => {
    clearTimeouts();
    setPhase('idle');
    setCurrentStep(0);
    setCompletedSteps([]);
    setDeployed(false);
    setDescription('');
  };

  const handleDeploy = () => setDeployed(true);

  const btnBase = {
    fontFamily: font,
    fontSize: 13,
    borderRadius: 6,
    padding: '8px 18px',
    cursor: 'pointer',
    fontWeight: 700,
    border: 'none',
    transition: 'opacity 0.15s',
  };

  return (
    <div style={{ background: C.bg, minHeight: '100vh', fontFamily: font, padding: 32, color: C.text }}>
      <div style={{ maxWidth: 680, margin: '0 auto' }}>
        {/* Header */}
        <div style={{ marginBottom: 32 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 4 }}>
            <span style={{ fontSize: 18 }}>⚡</span>
            <h1 style={{ margin: 0, fontSize: 22, fontWeight: 700 }}>Agentic Strategy Runner</h1>
            <span style={{
              fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 1,
              background: C.purple + '22', border: `1px solid ${C.purple}55`, color: C.purple,
              borderRadius: 6, padding: '2px 8px',
            }}>AI-Powered</span>
          </div>
          <p style={{ color: C.muted, fontSize: 13, margin: 0 }}>
            Describe a strategy in plain English. The engine parses, backtests, and deploys autonomously.
          </p>
        </div>

        {/* Input panel */}
        <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 14, padding: 20, marginBottom: 20 }}>
          <label style={{ fontSize: 11, color: C.muted, display: 'block', marginBottom: 8 }}>STRATEGY DESCRIPTION</label>
          <textarea
            value={description}
            onChange={e => setDescription(e.target.value)}
            placeholder={PLACEHOLDER}
            disabled={phase === 'running'}
            rows={4}
            style={{
              width: '100%',
              background: C.bg,
              border: `1px solid ${C.border}`,
              borderRadius: 10,
              color: C.text,
              fontFamily: font,
              fontSize: 13,
              padding: 12,
              resize: 'vertical',
              boxSizing: 'border-box',
              outline: 'none',
              lineHeight: 1.6,
              opacity: phase === 'running' ? 0.5 : 1,
            }}
          />
          <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: 12, gap: 12 }}>
            {phase !== 'idle' && (
              <button onClick={handleReset} style={{ ...btnBase, background: C.border, color: C.muted }}>
                Reset
              </button>
            )}
            <button
              onClick={handleBuild}
              disabled={phase === 'running' || !description.trim()}
              style={{
                ...btnBase,
                background: phase === 'running' || !description.trim() ? C.border : C.blue,
                color: phase === 'running' || !description.trim() ? C.muted : '#fff',
                cursor: phase === 'running' || !description.trim() ? 'not-allowed' : 'pointer',
              }}
            >
              {phase === 'running' ? 'Building...' : 'Build & Deploy'}
            </button>
          </div>
        </div>

        {/* Progress steps */}
        {(phase === 'running' || phase === 'done') && (
          <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 14, padding: 20, marginBottom: 20 }}>
            <div style={{ fontSize: 11, color: C.muted, marginBottom: 16, textTransform: 'uppercase', letterSpacing: 1 }}>Build Pipeline</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              {STEPS.map(step => {
                const done = completedSteps.includes(step.id);
                const active = currentStep === step.id;
                return (
                  <div key={step.id} style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                    <div style={{ width: 20, display: 'flex', justifyContent: 'center' }}>
                      {done ? <CheckIcon /> : active ? <Spinner /> : (
                        <div style={{ width: 8, height: 8, borderRadius: '50%', background: C.border, border: `1px solid ${C.muted}` }} />
                      )}
                    </div>
                    <span style={{
                      fontSize: 13,
                      color: done ? C.green : active ? C.blue : C.muted,
                      fontWeight: done || active ? 600 : 400,
                      transition: 'color 0.25s',
                    }}>
                      {step.id}. {step.label}
                    </span>
                    {done && step.id < 5 && (
                      <span style={{ fontSize: 10, color: C.muted, marginLeft: 'auto' }}>
                        {(Math.random() * 0.4 + 0.3).toFixed(2)}s
                      </span>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* Results card */}
        {phase === 'done' && (
          <div style={{
            background: C.surface,
            border: `1px solid ${C.green}55`,
            borderRadius: 14,
            padding: 20,
            boxShadow: `0 0 24px ${C.green}18`,
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
              <div>
                <div style={{ fontSize: 11, color: C.muted, textTransform: 'uppercase', letterSpacing: 1, marginBottom: 4 }}>Strategy Ready</div>
                <div style={{ fontSize: 14, fontWeight: 700, color: C.green }}>{MOCK_RESULTS.name}</div>
              </div>
              {deployed && (
                <span style={{
                  fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 1,
                  background: C.green + '22', border: `1px solid ${C.green}55`, color: C.green,
                  borderRadius: 6, padding: '3px 10px',
                }}>LIVE</span>
              )}
            </div>

            {/* Metrics grid */}
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, marginBottom: 16 }}>
              <MetricTile label="Sharpe" value={MOCK_RESULTS.sharpe} color={C.blue} />
              <MetricTile label="Profit Factor" value={MOCK_RESULTS.pf} color={C.green} />
              <MetricTile label="Win Rate" value={MOCK_RESULTS.winRate} color={C.green} />
              <MetricTile label="CAGR" value={MOCK_RESULTS.cagr} color={C.amber} />
              <MetricTile label="Max DD" value={MOCK_RESULTS.maxDD} color={C.red} />
              <MetricTile label="Trades" value={MOCK_RESULTS.trades} />
            </div>

            {/* Action buttons */}
            <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
              <button
                onClick={handleDeploy}
                disabled={deployed}
                style={{
                  ...btnBase,
                  background: deployed ? C.green + '33' : C.green,
                  color: deployed ? C.green : '#000',
                  cursor: deployed ? 'default' : 'pointer',
                }}
              >
                {deployed ? '✓ Deployed' : 'Deploy'}
              </button>
              <button
                onClick={() => { setPhase('idle'); setCompletedSteps([]); setCurrentStep(0); setDeployed(false); }}
                style={{ ...btnBase, background: C.blue + '22', border: `1px solid ${C.blue}55`, color: C.blue }}
              >
                Modify
              </button>
              <button
                onClick={handleReset}
                style={{ ...btnBase, background: C.red + '22', border: `1px solid ${C.red}55`, color: C.red }}
              >
                Discard
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
